module RefModule(
    input [3:0] A,
    input [3:0] B,
    output reg [3:0] S,  // Change to reg
    output C
);wire [3:0] unused_sum;
    wire carry;

    assign unused_sum = A + B;
    assign C = (A[3] & B[3]) | ((A[3] | B[3]) & ~unused_sum[3]);

    always @* begin
        if (C) begin
            S = unused_sum + 1;
        end else begin
            S = unused_sum;
        end
    end

endmodule
